// ============================================================================
// MAIN EXECUTION
// ============================================================================

async function runD1Query(sql: string): Promise<any> {
  const res = await fetch(D1_URL, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${CF_API_TOKEN}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ sql }),
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(`D1 API error ${res.status}: ${text}`);
  }
  return res.json();
}

function escapeSQL(s: string | null): string {
  if (s === null) return 'NULL';
  return `'${s.replace(/'/g, "''")}'`;
}

async function main() {
  console.log('=== MEGA Gateway Bulk Tool Population ===\n');

  // 1. Get all servers with no tools
  const result = await runD1Query(
    `SELECT s.id, s.server_name, s.category FROM servers s
     WHERE NOT EXISTS (SELECT 1 FROM tools t WHERE t.server_id = s.id)
     ORDER BY s.category, s.id`
  );

  const servers = result.result[0].results as { id: number; server_name: string; category: string }[];
  console.log(`Found ${servers.length} servers without tools\n`);

  let totalInserted = 0;
  const BATCH_SIZE = 15; // rows per INSERT

  // 2. For each server, generate tools from its category template
  const allRows: string[] = [];

  for (const server of servers) {
    const tools = CATEGORY_TOOLS[server.category];
    if (!tools) {
      console.log(`  SKIP: No template for category ${server.category}`);
      continue;
    }

    for (const tool of tools) {
      const row = `(${server.id},${escapeSQL(tool.tool_name)},${escapeSQL(tool.description)},${escapeSQL(tool.category)},${escapeSQL(tool.http_method)},${escapeSQL(tool.path_template)},${escapeSQL(tool.query_params_schema)},${escapeSQL(tool.body_schema)},${escapeSQL(tool.body_template)},${escapeSQL(tool.response_path)},${escapeSQL(tool.content_type)},${escapeSQL(tool.parameters)},1)`;
      allRows.push(row);
    }
  }

  console.log(`Generated ${allRows.length} tool rows to insert\n`);

  // 3. Batch insert
  for (let i = 0; i < allRows.length; i += BATCH_SIZE) {
    const batch = allRows.slice(i, i + BATCH_SIZE);
    const sql = `INSERT OR IGNORE INTO tools (server_id, tool_name, description, category, http_method, path_template, query_params_schema, body_schema, body_template, response_path, content_type, parameters, is_available) VALUES\n${batch.join(',\n')}`;

    try {
      await runD1Query(sql);
      totalInserted += batch.length;
      if ((i / BATCH_SIZE) % 50 === 0) {
        console.log(`  Inserted ${totalInserted}/${allRows.length} tools...`);
      }
    } catch (err: any) {
      console.error(`  ERROR at batch ${i}: ${err.message}`);
      // Try smaller batch on error
      for (const row of batch) {
        try {
          await runD1Query(`INSERT OR IGNORE INTO tools (server_id, tool_name, description, category, http_method, path_template, query_params_schema, body_schema, body_template, response_path, content_type, parameters, is_available) VALUES ${row}`);
        } catch { /* skip duplicates */ }
      }
    }
  }

  console.log(`\n=== DONE: Inserted ${totalInserted} tools ===`);

  // 4. Get final count
  const countResult = await runD1Query('SELECT COUNT(*) as total FROM tools');
  console.log(`Total tools in D1: ${countResult.result[0].results[0].total}`);

  // 5. Update server tool_count fields
  await runD1Query(`UPDATE servers SET tool_count = (SELECT COUNT(*) FROM tools WHERE tools.server_id = servers.id)`);
  console.log('Updated server tool_count fields');
}

main().catch(console.error);
